#include <stdio.h>
#include <string.h>
typedef struct { int pid; int uid; char cmd[32]; } ProcessRecord;
int main(void) {
    char buf[1024];
    memset(buf, 0, sizeof(buf));
    FILE *f = fmemopen(buf, sizeof(buf), "w+");
    if (!f) return 1;
    ProcessRecord procs[] = {
        {1,    0, "init"},
        {42,   1000, "bash"},
        {1337, 1000, "clings"}
    };
    for (int i = 0; i < 3; i++)
        fwrite(&procs[i], sizeof(ProcessRecord), 1, f);
    rewind(f);
    ProcessRecord r;
    printf("pid  uid  cmd\n");
    while (fread(&r, sizeof(ProcessRecord), 1, f) == 1)
        printf("%-4d %-4d %s\n", r.pid, r.uid, r.cmd);
    fclose(f);
    return 0;
}

