#include <stdio.h>
#include <string.h>

/* == EXEMPLE ================================================
 * Ecrire/lire des structs binaires avec fwrite/fread
 * fwrite(&s, sizeof(s), 1, f) ecrit sizeof(s) octets bruts
 * =========================================================== */
typedef struct { int id; float temp; } SensorReading;

void example_binary_sensor(void) {
    char sbuf[512];
    memset(sbuf, 0, sizeof(sbuf));
    FILE *sf = fmemopen(sbuf, sizeof(sbuf), "w+");
    if (!sf) return;
    SensorReading sensors[] = {
        {1, 22.5f}, {2, 18.3f}, {3, 30.1f}
    };
    for (int i = 0; i < 3; i++)
        fwrite(&sensors[i], sizeof(SensorReading), 1, sf);
    rewind(sf);
    SensorReading s;
    while (fread(&s, sizeof(SensorReading), 1, sf) == 1)
        printf("Sensor %d: %.1f C\n", s.id, s.temp);
    fclose(sf);
}
/* Resultat: Sensor 1: 22.5 C, Sensor 2: 18.3 C, Sensor 3: 30.1 C */

